payload.text:
To address your request, I will modify `App.tsx` to disable automatic camera access by default. I will add a manual "Camera On/Off" toggle button to the **Create Reference** and **Monitor** views.

Here are the specific changes:
1.  **State Management**: Added `isCameraEnabled` state (defaulting to `false`).
2.  **Effect Logic**: Updated the camera initialization effect to only start the stream if `isCameraEnabled` is true.
3.  **UI Updates**:
    *   Added a **Camera Toggle Button** in the toolbar for both scanning and monitoring pages.
    *   Added a **Placeholder Screen** in the video area when the camera is turned off, so the UI doesn't look broken.
    *   Ensured monitoring automatically stops if the camera is turned off.

# Updated files:

## App.tsx

```tsx
import React, { useState, useRef, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import BoundingBoxOverlay from './components/BoundingBoxOverlay';
import { detectObjectsInScene, compareScenes } from './services/geminiService';
import { SceneReference, DetectedObject, ViewMode, ObjectStatus } from './types';
import { Camera, Save, Trash2, Play, Pause, Upload, Loader2, Eye, Images, CameraOff } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>('dashboard');
  const [references, setReferences] = useState<SceneReference[]>([]);
  const [activeRefId, setActiveRefId] = useState<string | null>(null);

  // Camera & Image State
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [availableDevices, setAvailableDevices] = useState<MediaDeviceInfo[]>([]);
  const [selectedDeviceId, setSelectedDeviceId] = useState<string>('');
  const [isCameraEnabled, setIsCameraEnabled] = useState(false);

  // Processing State
  const [isProcessing, setIsProcessing] = useState(false);
  const [detectedObjects, setDetectedObjects] = useState<DetectedObject[]>([]);
  const [currentFrameImage, setCurrentFrameImage] = useState<string | null>(null);
  const [monitoringActive, setMonitoringActive] = useState(false);

  // Photo Compare State
  const [photoCompareRef, setPhotoCompareRef] = useState<string | null>(null);
  const [photoCompareLive, setPhotoCompareLive] = useState<string | null>(null);
  const [photoCompareResults, setPhotoCompareResults] = useState<DetectedObject[]>([]);

  // Initialize Camera Devices
  useEffect(() => {
    const getDevices = async () => {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const videoDevices = devices.filter(d => d.kind === 'videoinput');
        setAvailableDevices(videoDevices);
        if (videoDevices.length > 0) setSelectedDeviceId(videoDevices[0].deviceId);
      } catch (err) {
        console.error("Error enumerating devices:", err);
      }
    };
    getDevices();
    return () => stopStream();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Handle Stream Start/Stop
  const startStream = async (deviceId?: string) => {
    stopStream();
    try {
      const constraints = {
        video: { deviceId: deviceId ? { exact: deviceId } : undefined, width: 1280, height: 720 }
      };
      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);
      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
      }
    } catch (err) {
      console.error("Camera error:", err);
      setIsCameraEnabled(false); // Revert if failed
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopStream = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  // Effect to handle camera toggle based on view and enablement state
  useEffect(() => {
    if ((view === 'create-reference' || view === 'monitor') && isCameraEnabled) {
      startStream(selectedDeviceId);
    } else {
      stopStream();
      setMonitoringActive(false); // Stop monitoring if camera goes off
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view, selectedDeviceId, isCameraEnabled]);

  // Turn off camera when switching main views to prevent background usage
  useEffect(() => {
    setIsCameraEnabled(false);
  }, [view]);

  // Helper: Capture Frame
  const captureFrame = useCallback((): string | null => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      if (video.videoWidth === 0 || video.videoHeight === 0) return null;

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        return dataUrl;
      }
    }
    return null;
  }, []);

  // --- Actions ---

  const handleCaptureReference = async () => {
    const dataUrl = captureFrame();
    if (!dataUrl) return;

    setIsProcessing(true);
    setCurrentFrameImage(dataUrl);

    try {
      // Strip prefix for API
      const base64 = dataUrl.split(',')[1];
      const objects = await detectObjectsInScene(base64);
      setDetectedObjects(objects);
    } catch (err) {
      console.error(err);
      alert("Failed to analyze scene. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveReference = (name: string) => {
    if (!currentFrameImage) return;
    const newRef: SceneReference = {
      id: Date.now().toString(),
      name: name || `Reference ${references.length + 1}`,
      imageData: currentFrameImage,
      createdAt: Date.now(),
      objects: detectedObjects
    };
    setReferences([...references, newRef]);
    setView('dashboard');
    setCurrentFrameImage(null);
    setDetectedObjects([]);
  };

  const performScan = useCallback(async () => {
    const activeRef = references.find(r => r.id === activeRefId);
    if (!activeRef) return;

    const liveFrame = captureFrame();
    if (!liveFrame) return;

    setIsProcessing(true); 

    try {
      const refBase64 = activeRef.imageData.split(',')[1];
      const liveBase64 = liveFrame.split(',')[1];

      const comparisonResults = await compareScenes(refBase64, liveBase64);
      setDetectedObjects(comparisonResults);
    } catch (err) {
      console.error("Scan failed", err);
    } finally {
      setIsProcessing(false);
    }
  }, [activeRefId, references, captureFrame]);

  const toggleMonitoring = () => {
    if (monitoringActive) {
      setMonitoringActive(false);
    } else {
      if (!isCameraEnabled) {
        alert("Please turn on the camera first.");
        return;
      }
      if (!activeRefId) {
        alert("Please select a reference scene first.");
        return;
      }
      setMonitoringActive(true);
    }
  };

  // Monitoring Interval Effect
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (monitoringActive && isCameraEnabled) {
      performScan(); // Immediate scan on start
      interval = setInterval(performScan, 5000); // Repeat every 5s
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [monitoringActive, isCameraEnabled, performScan]);

  const handlePhotoCompare = async () => {
    if (!photoCompareRef || !photoCompareLive) return;
    setIsProcessing(true);
    try {
      const refBase64 = photoCompareRef.split(',')[1];
      const liveBase64 = photoCompareLive.split(',')[1];
      const results = await compareScenes(refBase64, liveBase64);
      setPhotoCompareResults(results);
    } catch (err) {
      console.error(err);
      alert("Comparison failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'ref' | 'live') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (target === 'ref') setPhotoCompareRef(reader.result as string);
        else setPhotoCompareLive(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };


  // --- Render Views ---

  const renderDashboard = () => (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <button onClick={() => setView('create-reference')} className="group relative overflow-hidden bg-fog-panel p-6 rounded-2xl shadow-lg border border-white/5 hover:border-fog-accent/30 transition-all text-left">
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <Camera className="w-24 h-24 text-fog-accent" />
          </div>
          <div className="bg-fog-base/50 w-12 h-12 rounded-xl flex items-center justify-center text-fog-accent mb-4 border border-white/5">
            <Camera className="w-6 h-6" />
          </div>
          <h3 className="text-lg font-bold text-white/90">Create Reference</h3>
          <p className="text-fog-accent/60 text-sm mt-2">Scan a new area or object to monitor.</p>
        </button>

        <button onClick={() => setView('monitor')} className="group relative overflow-hidden bg-fog-panel p-6 rounded-2xl shadow-lg border border-white/5 hover:border-fog-accent/30 transition-all text-left">
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <Eye className="w-24 h-24 text-status-present" />
          </div>
          <div className="bg-fog-base/50 w-12 h-12 rounded-xl flex items-center justify-center text-status-present mb-4 border border-white/5">
             <Eye className="w-6 h-6" />
          </div>
          <h3 className="text-lg font-bold text-white/90">Start Monitoring</h3>
          <p className="text-fog-accent/60 text-sm mt-2">Live comparison against saved scenes.</p>
        </button>

        <button onClick={() => setView('photo-compare')} className="group relative overflow-hidden bg-fog-panel p-6 rounded-2xl shadow-lg border border-white/5 hover:border-fog-accent/30 transition-all text-left">
           <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <Images className="w-24 h-24 text-status-new" />
          </div>
          <div className="bg-fog-base/50 w-12 h-12 rounded-xl flex items-center justify-center text-status-new mb-4 border border-white/5">
            <Images className="w-6 h-6" />
          </div>
          <h3 className="text-lg font-bold text-white/90">Photo Compare</h3>
          <p className="text-fog-accent/60 text-sm mt-2">Upload two static images to find differences.</p>
        </button>
      </div>

      <div>
        <h2 className="text-xl font-bold text-white/90 mb-4 tracking-tight">Saved References</h2>
        {references.length === 0 ? (
          <div className="text-center py-12 bg-fog-panel rounded-2xl border border-dashed border-white/10">
            <p className="text-fog-accent/40">No references saved yet.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {references.map(ref => (
              <div key={ref.id} className="bg-fog-panel rounded-xl shadow-lg border border-white/5 overflow-hidden group hover:border-fog-accent/20 transition-all">
                <div className="relative h-48 bg-fog-base">
                  <img src={ref.imageData} alt={ref.name} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-black/40 group-hover:bg-black/60 transition-all flex items-center justify-center opacity-0 group-hover:opacity-100 backdrop-blur-sm">
                      <button onClick={() => { setActiveRefId(ref.id); setView('monitor'); }} className="bg-fog-accent text-fog-base px-6 py-2 rounded-lg font-bold text-sm shadow-lg hover:scale-105 transition-transform border border-white/20">
                        Monitor This
                      </button>
                  </div>
                </div>
                <div className="p-4 flex items-center justify-between">
                  <div>
                    <h4 className="font-bold text-white/90">{ref.name}</h4>
                    <p className="text-xs text-fog-accent/60">{ref.objects.length} objects tracked</p>
                  </div>
                  <button onClick={() => setReferences(references.filter(r => r.id !== ref.id))} className="text-fog-accent/40 hover:text-status-missing p-2 transition-colors">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  const renderCreateReference = () => (
    <div className="flex flex-col h-full space-y-4">
      <div className="flex justify-between items-center bg-fog-panel p-4 rounded-xl shadow-lg border border-white/5">
        <div>
           <h2 className="font-bold text-white/90">New Reference Scene</h2>
           <p className="text-sm text-fog-accent/60">Align camera and capture the standard state.</p>
        </div>
        <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsCameraEnabled(!isCameraEnabled)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-sm transition-colors border ${
                isCameraEnabled 
                ? 'bg-fog-base text-fog-accent border-fog-accent/20' 
                : 'bg-fog-accent text-fog-base border-transparent hover:bg-white'
              }`}
            >
               {isCameraEnabled ? <><Camera className="w-4 h-4"/> Camera On</> : <><CameraOff className="w-4 h-4"/> Camera Off</>}
            </button>
            <select 
              disabled={!isCameraEnabled}
              className="bg-fog-base border border-white/10 rounded-lg px-3 py-2 text-sm text-fog-accent focus:ring-1 focus:ring-fog-accent outline-none disabled:opacity-50"
              value={selectedDeviceId}
              onChange={(e) => setSelectedDeviceId(e.target.value)}
            >
              {availableDevices.map(d => (
                <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId.slice(0,5)}...`}</option>
              ))}
            </select>
        </div>
      </div>

      <div className="flex-1 flex gap-6 overflow-hidden">
        {/* Camera View */}
        <div className="flex-1 bg-black rounded-2xl overflow-hidden relative shadow-2xl shadow-black/50 flex items-center justify-center border border-white/5">
            {currentFrameImage ? (
               <div className="relative w-full h-full">
                 <img src={currentFrameImage} alt="Captured" className="w-full h-full object-contain opacity-90" />
                 <BoundingBoxOverlay objects={detectedObjects} containerWidth={100} containerHeight={100} />
               </div>
            ) : isCameraEnabled ? (
               <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-contain opacity-90" />
            ) : (
               <div className="flex flex-col items-center justify-center text-fog-accent/40 space-y-2">
                  <CameraOff className="w-16 h-16 opacity-50" />
                  <p>Camera disabled</p>
               </div>
            )}

            {isProcessing && (
              <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center text-fog-accent z-20">
                <Loader2 className="w-10 h-10 animate-spin mb-2" />
                <p>Analyzing Scene...</p>
              </div>
            )}

            {/* Capture Controls Overlay */}
            {!currentFrameImage && isCameraEnabled && (
              <div className="absolute bottom-6 left-0 right-0 flex justify-center z-10">
                 <button onClick={handleCaptureReference} className="bg-fog-panel/50 backdrop-blur-md rounded-full p-4 shadow-xl border border-white/10 hover:scale-110 transition-transform active:scale-95 group">
                   <div className="w-12 h-12 rounded-full border-4 border-fog-accent group-hover:bg-fog-accent/20 transition-colors"></div>
                 </button>
              </div>
            )}
        </div>

        {/* Sidebar Controls */}
        <div className="w-80 bg-fog-panel rounded-2xl shadow-lg border border-white/5 flex flex-col overflow-hidden shrink-0">
           <div className="p-4 border-b border-white/5 font-semibold text-white/90 bg-fog-base/30">
             Detected Objects
           </div>
           <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {detectedObjects.length > 0 ? (
                detectedObjects.map((obj, i) => (
                  <div key={i} className="flex items-center gap-3 p-3 rounded-lg border border-white/5 bg-fog-base/50 hover:bg-fog-base transition-colors">
                    <div className="w-8 h-8 rounded bg-fog-accent/10 text-fog-accent flex items-center justify-center font-bold text-xs border border-fog-accent/20">
                      {i + 1}
                    </div>
                    <input 
                      className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-medium text-white/80 p-0 placeholder-white/20"
                      value={obj.label}
                      onChange={(e) => {
                        const newObjs = [...detectedObjects];
                        newObjs[i].label = e.target.value;
                        setDetectedObjects(newObjs);
                      }}
                    />
                    <button 
                       onClick={() => {
                         const newObjs = [...detectedObjects];
                         newObjs[i].userHidden = !newObjs[i].userHidden;
                         setDetectedObjects(newObjs);
                       }}
                       className={`p-1.5 rounded-md ${obj.userHidden ? 'text-fog-accent/40 bg-fog-base' : 'text-fog-accent bg-fog-accent/10'}`}
                    >
                      <Eye className={`w-4 h-4 ${obj.userHidden ? 'strike-through' : ''}`} />
                    </button>
                  </div>
                ))
              ) : (
                <div className="text-center text-fog-accent/40 text-sm mt-10 italic">
                  {currentFrameImage ? "No objects detected." : isCameraEnabled ? "Capture an image to detect objects." : "Turn on camera to start."}
                </div>
              )}
           </div>

           <div className="p-4 border-t border-white/5 space-y-3 bg-fog-base/30">
              {currentFrameImage ? (
                <>
                  <button onClick={() => { setCurrentFrameImage(null); setDetectedObjects([]); }} className="w-full py-2.5 rounded-xl border border-white/10 text-fog-accent font-medium hover:bg-white/5 transition-colors">
                    Retake
                  </button>
                  <button onClick={() => handleSaveReference(prompt("Name this reference scene:", "My Workspace") || "")} className="w-full py-2.5 rounded-xl bg-fog-accent text-fog-base font-bold hover:bg-white transition-colors shadow-lg shadow-fog-accent/10">
                    Save Reference
                  </button>
                </>
              ) : null}
           </div>
        </div>
      </div>
    </div>
  );

  const renderMonitor = () => (
    <div className="flex flex-col h-full space-y-4">
      {/* Top Bar */}
      <div className="flex justify-between items-center bg-fog-panel p-4 rounded-xl shadow-lg border border-white/5">
         <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsCameraEnabled(!isCameraEnabled)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-sm transition-colors border ${
                isCameraEnabled 
                ? 'bg-fog-base text-fog-accent border-fog-accent/20' 
                : 'bg-fog-accent text-fog-base border-transparent hover:bg-white'
              }`}
            >
               {isCameraEnabled ? <><Camera className="w-4 h-4"/> Camera On</> : <><CameraOff className="w-4 h-4"/> Camera Off</>}
            </button>

            <select 
              className="bg-fog-base border border-white/10 rounded-lg px-3 py-2 text-sm font-medium text-fog-accent focus:ring-1 focus:ring-fog-accent outline-none min-w-[200px]"
              value={activeRefId || ''}
              onChange={(e) => { setActiveRefId(e.target.value); setDetectedObjects([]); }}
            >
              <option value="" disabled>Select Reference...</option>
              {references.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
            </select>

            {activeRefId && (
               <div className="flex items-center gap-2 text-sm text-fog-accent/60">
                  <span className="w-1.5 h-1.5 rounded-full bg-fog-accent"></span>
                  <span>{references.find(r => r.id === activeRefId)?.objects.length} tracked items</span>
               </div>
            )}
         </div>

         <div className="flex items-center gap-3">
             {monitoringActive && (
               <div className="flex items-center gap-2 px-3 py-1.5 bg-status-missing/10 text-status-missing rounded-full text-xs font-bold animate-pulse border border-status-missing/20">
                  <div className="w-2 h-2 rounded-full bg-status-missing"></div>
                  LIVE
               </div>
             )}

             <button 
               onClick={toggleMonitoring}
               className={`flex items-center gap-2 px-5 py-2 rounded-lg font-bold text-sm transition-colors shadow-lg ${
                 monitoringActive 
                 ? 'bg-status-missing/20 text-status-missing border border-status-missing/50 hover:bg-status-missing/30' 
                 : 'bg-status-present/20 text-status-present border border-status-present/50 hover:bg-status-present/30'
               }`}
             >
               {monitoringActive ? <><Pause className="w-4 h-4"/> Stop</> : <><Play className="w-4 h-4"/> Start Monitor</>}
             </button>
         </div>
      </div>

      <div className="flex-1 flex gap-6 overflow-hidden">
        {/* Main Comparison View */}
        <div className="flex-1 flex gap-1 bg-black rounded-2xl overflow-hidden border border-white/5 shadow-2xl">
           {/* Reference (Small Overlay or Split) - Let's do Split for clarity */}
           <div className="w-1/3 bg-fog-base border-r border-white/5 overflow-hidden relative grayscale opacity-70">
              <div className="absolute top-4 left-4 z-10 bg-black/60 text-white/80 text-xs px-2 py-1 rounded backdrop-blur-sm border border-white/10">Reference</div>
              {activeRefId && references.find(r => r.id === activeRefId) ? (
                 <img 
                   src={references.find(r => r.id === activeRefId)?.imageData} 
                   className="w-full h-full object-cover"
                   alt="Reference"
                 />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-fog-accent/40 text-sm">Select Reference</div>
              )}
           </div>

           {/* Live Feed */}
           <div className="flex-1 bg-black overflow-hidden relative flex items-center justify-center">
             <div className="absolute top-4 left-4 z-10 bg-status-missing/80 text-white text-xs px-2 py-1 rounded backdrop-blur-sm animate-pulse">Live Feed</div>

             {isCameraEnabled ? (
                <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
             ) : (
                <div className="flex flex-col items-center justify-center text-fog-accent/40 space-y-2">
                  <CameraOff className="w-12 h-12 opacity-50" />
                  <p className="text-sm">Camera is off</p>
               </div>
             )}

             {/* Overlay for detections */}
             <BoundingBoxOverlay objects={detectedObjects} containerWidth={100} containerHeight={100} />

             {isProcessing && !monitoringActive && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/60 text-fog-accent backdrop-blur-sm">
                  <Loader2 className="w-8 h-8 animate-spin" />
                </div>
             )}
             {monitoringActive && isProcessing && (
                 <div className="absolute top-4 right-4 z-20">
                    <Loader2 className="w-5 h-5 animate-spin text-white" />
                 </div>
             )}
           </div>
        </div>

        {/* Status Panel */}
        <div className="w-72 bg-fog-panel rounded-2xl shadow-lg border border-white/5 flex flex-col overflow-hidden shrink-0">
          <div className="p-4 border-b border-white/5 font-semibold text-white/90 bg-fog-base/30">
            Status Report
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {/* Stats */}
            <div className="grid grid-cols-3 gap-2 text-center text-xs font-bold text-fog-base">
               <div className="bg-status-missing p-2 rounded-lg">{detectedObjects.filter(o => o.status === ObjectStatus.MISSING).length} Missing</div>
               <div className="bg-status-new p-2 rounded-lg">{detectedObjects.filter(o => o.status === ObjectStatus.NEW).length} New</div>
               <div className="bg-status-present p-2 rounded-lg">{detectedObjects.filter(o => o.status === ObjectStatus.PRESENT).length} OK</div>
            </div>

            {/* List */}
            <div className="space-y-2 mt-4">
              {detectedObjects.map((obj, i) => (
                <div key={i} className={`flex items-center justify-between p-2.5 rounded-lg border text-sm ${
                   obj.status === ObjectStatus.MISSING ? 'bg-status-missing/10 border-status-missing/20 text-status-missing' :
                   obj.status === ObjectStatus.NEW ? 'bg-status-new/10 border-status-new/20 text-status-new' :
                   'bg-fog-base border-white/5 text-fog-accent'
                }`}>
                   <span className="font-medium truncate pr-2">{obj.label}</span>
                   <span className={`text-[10px] uppercase font-bold px-1.5 py-0.5 rounded border opacity-70 ${
                      obj.status === ObjectStatus.MISSING ? 'border-status-missing text-status-missing' :
                      obj.status === ObjectStatus.NEW ? 'border-status-new text-status-new' :
                      'border-fog-accent/50 text-fog-accent'
                   }`}>
                     {obj.status}
                   </span>
                </div>
              ))}
