import React, { useState, useRef, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import BoundingBoxOverlay from './components/BoundingBoxOverlay';
import { detectObjectsInScene, compareScenes } from './services/geminiService';
import { SceneReference, DetectedObject, ViewMode, ObjectStatus } from './types';
import { Camera, Save, Trash2, Play, Pause, Upload, Loader2, Eye, Images, CameraOff, AlertCircle, Edit2 } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>('dashboard');
  const [references, setReferences] = useState<SceneReference[]>([]);
  const [activeRefId, setActiveRefId] = useState<string | null>(null);

  // Camera & Image State
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [availableDevices, setAvailableDevices] = useState<MediaDeviceInfo[]>([]);
  const [selectedDeviceId, setSelectedDeviceId] = useState<string>('');
  const [isCameraEnabled, setIsCameraEnabled] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  // Processing State
  const [isProcessing, setIsProcessing] = useState(false);
  const [detectedObjects, setDetectedObjects] = useState<DetectedObject[]>([]);
  const [currentFrameImage, setCurrentFrameImage] = useState<string | null>(null);
  const [monitoringActive, setMonitoringActive] = useState(false);

  // Photo Compare State
  const [photoCompareRef, setPhotoCompareRef] = useState<string | null>(null);
  const [photoCompareLive, setPhotoCompareLive] = useState<string | null>(null);
  const [photoCompareResults, setPhotoCompareResults] = useState<DetectedObject[]>([]);

  // Initialize Camera Devices
  useEffect(() => {
    const getDevices = async () => {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const videoDevices = devices.filter(d => d.kind === 'videoinput');
        setAvailableDevices(videoDevices);
        if (videoDevices.length > 0) setSelectedDeviceId(videoDevices[0].deviceId);
      } catch (err) {
        console.error("Error enumerating devices:", err);
        setCameraError("Could not list camera devices. Please check permissions.");
      }
    };
    getDevices();
    return () => stopStream();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Handle Stream Start/Stop
  const startStream = async (deviceId?: string) => {
    stopStream();
    setCameraError(null);
    try {
      const constraints = {
        video: { 
          deviceId: deviceId ? { exact: deviceId } : undefined, 
          width: { ideal: 1280 }, 
          height: { ideal: 720 } 
        }
      };
      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);
      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
      }
    } catch (err: any) {
      console.error("Camera error:", err);
      setIsCameraEnabled(false);

      let errorMessage = "An unknown error occurred while accessing the camera.";
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') errorMessage = "Camera access denied. Please allow camera permissions.";
      else if (err.name === 'NotFoundError') errorMessage = "No camera found.";
      else if (err.name === 'NotReadableError') errorMessage = "Camera is currently in use by another application.";

      setCameraError(errorMessage);
    }
  };

  const stopStream = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  // Logic to handle camera state
  useEffect(() => {
    if ((view === 'create-reference' || view === 'monitor') && isCameraEnabled) {
      startStream(selectedDeviceId);
    } else {
      stopStream();
      setMonitoringActive(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view, selectedDeviceId, isCameraEnabled]);

  useEffect(() => {
    // When switching views, turn off camera and stop monitoring
    setIsCameraEnabled(false);
    setMonitoringActive(false);
    setCameraError(null);
    setDetectedObjects([]);
  }, [view]);

  // Helper: Capture Frame
  const captureFrame = useCallback((): string | null => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      if (video.videoWidth === 0 || video.videoHeight === 0) return null;

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        return dataUrl;
      }
    }
    return null;
  }, []);

  // --- Actions ---

  const handleCaptureReference = async () => {
    const dataUrl = captureFrame();
    if (!dataUrl) return;

    setIsProcessing(true);
    setCurrentFrameImage(dataUrl);

    try {
      const base64 = dataUrl.split(',')[1];
      const objects = await detectObjectsInScene(base64);
      setDetectedObjects(objects);
    } catch (err) {
      console.error(err);
      alert("Failed to analyze scene. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveReference = (name: string) => {
    if (!currentFrameImage) return;
    const newRef: SceneReference = {
      id: Date.now().toString(),
      name: name || `Reference ${references.length + 1}`,
      imageData: currentFrameImage,
      createdAt: Date.now(),
      objects: detectedObjects
    };
    setReferences([...references, newRef]);
    setView('dashboard');
    setCurrentFrameImage(null);
    setDetectedObjects([]);
  };

  const handleRenameReference = (id: string, newName: string) => {
    if (!newName) return;
    setReferences(references.map(ref => 
      ref.id === id ? { ...ref, name: newName } : ref
    ));
  };

  const performScan = useCallback(async () => {
    const activeRef = references.find(r => r.id === activeRefId);
    if (!activeRef) return;

    const liveFrame = captureFrame();
    if (!liveFrame) return;

    setIsProcessing(true); 

    try {
      const refBase64 = activeRef.imageData.split(',')[1];
      const liveBase64 = liveFrame.split(',')[1];

      const comparisonResults = await compareScenes(refBase64, liveBase64);
      setDetectedObjects(comparisonResults);
    } catch (err) {
      console.error("Scan failed", err);
    } finally {
      setIsProcessing(false);
    }
  }, [activeRefId, references, captureFrame]);

  const toggleMonitoring = () => {
    if (monitoringActive) {
      setMonitoringActive(false);
    } else {
      if (!isCameraEnabled) {
        setCameraError("Please turn on the camera first to start monitoring.");
        return;
      }
      if (!activeRefId) {
        alert("Please select a reference scene first.");
        return;
      }
      setMonitoringActive(true);
    }
  };

  // Monitoring Interval Effect
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (monitoringActive && isCameraEnabled) {
      performScan(); 
      interval = setInterval(performScan, 5000); 
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [monitoringActive, isCameraEnabled, performScan]);

  const handlePhotoCompare = async () => {
    if (!photoCompareRef || !photoCompareLive) return;
    setIsProcessing(true);
    try {
      const refBase64 = photoCompareRef.split(',')[1];
      const liveBase64 = photoCompareLive.split(',')[1];
      const results = await compareScenes(refBase64, liveBase64);
      setPhotoCompareResults(results);
    } catch (err) {
      console.error(err);
      alert("Comparison failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'ref' | 'live') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (target === 'ref') setPhotoCompareRef(reader.result as string);
        else setPhotoCompareLive(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };


  // --- Render Views ---

  const renderDashboard = () => (
    <div className="space-y-8 pb-10">
