                  <BoundingBoxOverlay objects={photoCompareResults} containerWidth={100} containerHeight={100} />
               </div>
             ) : (
               <div className="text-fog-accent/20 flex flex-col items-center">
                  <Eye className="w-16 h-16 mb-4 opacity-50" />
                  <span className="font-medium">Comparison result will appear here</span>
               </div>
             )}
          </div>
       </div>
    </div>
  );

  return (
    <Layout currentView={view} onChangeView={setView}>
      <canvas ref={canvasRef} className="hidden" />

      {view === 'dashboard' && renderDashboard()}
      {view === 'create-reference' && renderCreateReference()}
      {view === 'monitor' && renderMonitor()}
      {view === 'photo-compare' && renderPhotoCompare()}

    </Layout>
  );
};

export default App;
